+
+/**
+ * State change event emitted by the ingest service.
+ */
+export interface NtmStateChangeEvent {
+  type: "ntm.agent.state_changed" | "ntm.agent.health_changed";
+  pane: string;
+  sessionName: string;
+  agentType: string;
+  previousValue: string;
+  newValue: string;
+  timestamp: Date;
