+        } else if (targetState === LifecycleState.EXECUTING) {
+          reason = "ntm_working";
+        } else if (targetState === LifecycleState.FAILED) {
+          reason = "ntm_error";
+        } else if (targetState === LifecycleState.PAUSED) {
+          reason = "ntm_stalled";
+        } else {
+          reason = "ntm_state_change";
