+  ): void {
+    const log = getLogger();
+
+    // Cast panes to proper type - NtmTailOutput.panes is Record<string, PaneOutput>
+    const panes = tailOutput.panes as Record<string, PaneOutput>;
+
+    for (const agent of agents) {
+      const agentId = agent.gatewayAgentId;
+      if (!agentId) continue;
