+      if (opts?.ids) pushRepeated(args, "--id", opts.ids);
+      if (opts?.labels) pushRepeated(args, "--label", opts.labels);
+      if (opts?.labelsAny) pushRepeated(args, "--label-any", opts.labelsAny);
+      if (opts?.priorities)
+        pushRepeated(args, "--priority", opts.priorities);
